// auto-generated from reasonix
const QUESTIONS_POLITICS_2021 = [
  { id:'pol-2021-1', year:2021, subject:'po', topic:'po-1', type:'single', question:'马克思和恩格斯首次系统阐述历史唯物主义基本观点的著作A.德意志意识形态 B.神圣家族 C.哲学的贫困 D.共产党宣言', options:["A. 德意志意识形态 B.神圣家族 C.哲学的贫困 D.共产党宣言"], answer:'A', analysis:'A 选项，《德意志意识形态》是马克思、恩格斯对费尔巴哈为代表的各式各样唯心史观的思想进行批判的著作,该著作首次系统阐述了唯物史观的基本内容，标志着唯物史观的创立。B 选项，《神圣家族》是马克思和恩格斯第一次合写的批判青年黑格尔派主观唯心主义和论述历史唯物主义的著作。C 选项，《哲学的贫困》是为批判蒲鲁东的《贫困的哲学》而写的著作。该著作是马克思主义学说最早发表的文本。D 选项,《共产党宣言》发表于 1848 年，标志着马克思主义的公开问世。' },
  { id:'pol-2021-2', year:2021, subject:'po', topic:'po-1', type:'single', question:'人们能从历史中汲取经验教训是因为A.历史规律和自然规律有惊人的相似B.人类历史发展存在着不以人的意志为转移的规律C.历史总是在循环往复中不断向前发展D.人类已经完全掌握了历史发展的内在规律', options:["A. 历史规律和自然规律有惊人的相似B.人类历史发展存在着不以人的意志为转移的规律C.历史总是在循环往复中不断向前发展D.人类已经完全掌握了历史发展的内在规律"], answer:'B', analysis:'A 选项说法有误，历史规律与自然规律是不同的。自然规律起作用是自发的，离开了人的活动也同样起作用，而历史规律起作用离不开人的有有目的，有意识的活动的参与。B 选项说法正确，人们之所以能从历史中汲取经验教训正是由于历史的发展有着不以人的意志为转移的规律,发挥能动性就能认识和把握这些规律。C 选项说法有误,事物的发展是波浪式前进和螺旋式上升的,是前进性与曲折性的统一，历史的发展同样如此，并不是循环往复的。D 选项说法有误，认识发展具有无限性和反复性，人类还没有完全掌握历史发展的内在规律。' },
  { id:'pol-2021-3', year:2021, subject:'po', topic:'po-1', type:'single', question:'从社会意识和社会存在的关系看，法律法规A.总是阻碍新技术的健康发展 B.只能落后于新技术发展C.与新技术发展具有不平衡性 D.归根到底是新技术发展的内在动力', options:["A. 总是阻碍新技术的健康发展 B.只能落后于新技术发展C.与新技术发展具有不平衡性 D.归根到底是新技术发展的内在动力"], answer:'C', analysis:'A 选项有误，法律法规作为并不总是阻碍新技术发展的，当法律法规适应了技术进步的要求就会对技术进步产生促进作用。B 选项有误，社会意识与社会存在总发展员有不平彻性，法律法规作为社象临融。特定类型，有时会早于技术发展的变迁而变化，有时会晚于技术发展而变化，并不总是落后于新技术发展。D 选项有误，法律法规的变化发展归根到底是受到生产力发展水平制约的。' },
  { id:'pol-2021-4', year:2021, subject:'po', topic:'po-1', type:'single', question:'马克思指出：资本主义在发展“社会劳动的生产力 ”的同时进而不自觉的创造着一种更高级的生产形式的物质条件，这表明：A.资本主义生产方式能够无限制解放和发展社会生产力B.资本越发展越有利于巩固资本主义C.资本越扩张越不利于创造更多的物质财富D.资本主义生产是一种历史的、过渡性生产形式', options:["A. 资本主义生产方式能够无限制解放和发展社会生产力B.资本越发展越有利于巩固资本主义C.资本越扩张越不利于创造更多的物质财富D.资本主义生产是一种历史的、过渡性生产形式"], answer:'D', analysis:'A 选项有误，资本主义生产方式极大提高了生产力的水平，但不能由此就说，资本主义生产方式能够无限制解放发展生产力，随着生产力不断提高,资本主义内生性矛盾会不断凸显，最终推动资本主义走向灭亡。B 选项有误，资本主义不断发展，资本主义内生性矛盾也不断凸显，最终会推动资本主义走向灭亡。C 选项有误，资本主义生产方式下，生产力得到极大释放，有利于创造更多的物质财富，但也会带来负面效应,如贫富两极分化等社会问题。D 选项正确，资本主义生产方式极大提高了生产力水平，随着生产力不断得到解放，资本主义的生产关系会越来越不适应生产力的发展，最终生产力与生产关系的矛盾运动会推动资本主义走向解体,人类社会会进入到更高级的社会形态一—共产主义，因此说资本主义是一种过渡性的生产形式。' },
  { id:'pol-2021-5', year:2021, subject:'po', topic:'po-2', type:'single', question:'毛思想作为马克思主义中国化的第一个重大理论成果，是由一系列相互联系的重要理论观点所构成的科学思想体系这一科学体系所围绕的主题是A.中国革命和建设 B.中国命运和前途C.中国社会性质和阶段状况 D.中国改革和发展', options:["A. 中国革命和建设 B.中国命运和前途C.中国社会性质和阶段状况 D.中国改革和发展"], answer:'A', analysis:'没有中国革命和建设的丰富实践，没有对中国革命和建设经验的深刻总结，就可能有毛思想。正是经过长期实践的反复比较，党和人民选择了毛 作为自己的领袖，选择了毛思想作为自己的指导思想。中国共产党领导人民进行革命和建设的成功实践是毛思想形成和发展的实践基础。毛思想是被实践证明了的关于中国革命和建设的正确的理论原则和经验总结。故正确答案为 A。' },
  { id:'pol-2021-6', year:2021, subject:'po', topic:'po-2', type:'single', question:'构建新发展格局，是以习同志为核心的党中央积极应对国际国内形势变化，与时俱进提升我国经济发展水平，塑造国际经济全球和竞争新优势提出的战略决策，这一发展格局是A.以体制机制创新为主体，利用好国际国内两个市场B.以维护和平稳定为主体，促进国际国内经济复苏C.以国内大循环为主体，国内国际双循环相互促进D.以发展先进制造业为主体，促进产业结构优化升级', options:["A. 以体制机制创新为主体，利用好国际国内两个市场B.以维护和平稳定为主体，促进国际国内经济复苏C.以国内大循环为主体，国内国际双循环相互促进D.以发展先进制造业为主体，促进产业结构优化升级"], answer:'C', analysis:'中国的新发展格局是以国内大循环为主体、国内国际双循环相互促进的发展格局，绝不是封闭的国内循环，而是更加开放的国内国际双循环。故正确答案为 C。' },
  { id:'pol-2021-7', year:2021, subject:'po', topic:'po-2', type:'single', question:'改革开放初期，确立了公有制为主体的市场经济，多种所有制公共发展，按劳分配为主体，多种分配制度并存，社会市场经济制度等社会主义基本经济制度，这一基本经济制度中，坚持公有制的主体地位是因为A.公有制是社会主义市场经济的重要组成部分B.公有制是我国经济社会发展的重要基础C.生产资料所有制决定社会的基本性质和发展方向D.由生产资料所有制决定的分配方式能使一切社会成员实现全面发展', options:["A. 公有制是社会主义市场经济的重要组成部分B.公有制是我国经济社会发展的重要基础C.生产资料所有制决定社会的基本性质和发展方向D.由生产资料所有制决定的分配方式能使一切社会成员实现全面发展"], answer:'C', analysis:'坚持公有制的主体地位，是因为生产资料社会主义公有制是社会主义经济制度的基础，是社会主义经济制度的根本标志，它决定了我国社会主义的基本性质和发展方向，只有建立起社会主义公有制并使其在多种所有制经济中居于主体地位，才标志着社会主义经济制度真正建立起来。要坚持社会主义，必须坚持生产资料公有制;在社会主义初级阶段，必须坚持公有制的主体地位。故正确答案为 C。' },
  { id:'pol-2021-8', year:2021, subject:'po', topic:'po-2', type:'single', question:'创新是引领发展的第一动力，必须把创新摆在现代化建设全面的核心地位。 2020 年9 月 11 日习在《科学家座谈上讲话》中指出我国经济发展及改善民生比以往任何时候都需要加强创新这个第一动力，创造更多从“0 ”到“ 1 ”的突破，需要摆在更加突出位置的是A.提升原始创新能力 B.加快推进消化吸收再创新C.加强了企业创新主体地位 D.改善科技创新', options:["A. 提升原始创新能力 B.加快推进消化吸收再创新C.加强了企业创新主体地位 D.改善科技创新"], answer:'A', analysis:'时政与毛中特结合考察。2020 年9 月 15 日习主持召开科学家座谈会强调特别要把原始创新能力提升摆在更加突出的位置 努力实现更多“从 0 到1 ”的突破。' },
  { id:'pol-2021-9', year:2021, subject:'po', topic:'po-3', type:'single', question:'洋务运动时期，洋务派兴办了一些企业少数官办或官商合办，多数是官督商办，这些关督商办的企业是什么性质?A.封建性质企业 B.半封建 C.资本 D.社会性质', options:["A. 封建性质企业 B.半封建 C.资本 D.社会性质"], answer:'C', analysis:'洋务派兴办的企业广泛采用雇佣劳动，属于资本主义生产性质的企业。' },
  { id:'pol-2021-10', year:2021, subject:'po', topic:'po-3', type:'single', question:'中国人民抗战胜利的关键是A.民族意识的觉醒与全民的抗战 B.反侵压战争的正义性与进步性C.世界反法西斯力量的团结与支持 D.中国共产党中流砥柱的作用', options:["A. 民族意识的觉醒与全民的抗战 B.反侵压战争的正义性与进步性C.世界反法西斯力量的团结与支持 D.中国共产党中流砥柱的作用"], answer:'D', analysis:'抗战胜利的关键是中国共产党的中流砥柱作用' },
  { id:'pol-2021-11', year:2021, subject:'po', topic:'po-3', type:'single', question:'人民政协的召开标志着A.民族区域自治制度的建立 B.工商代表大会制度的建立C.人民代表大会制度的建立 D.新型政协制度的建立', options:["A. 民族区域自治制度的建立 B.工商代表大会制度的建立C.人民代表大会制度的建立 D.新型政协制度的建立"], answer:'D', analysis:'中国人民政治协商会议第一届全体会议于 1949 年 9 月在北京开幕，标志着新型政协制度的建立。' },
  { id:'pol-2021-12', year:2021, subject:'po', topic:'po-3', type:'single', question:'我国对资本主义工商业的社会主义改造执行的是A.互助合作政策 B.调整巩固 C.和平赎买 D.剥夺没收', options:["A. 互助合作政策 B.调整巩固 C.和平赎买 D.剥夺没收"], answer:'C', analysis:'1953 年-1956 年，对资本主义工商业的社会主义改造实行的是和平赎买政策。' },
  { id:'pol-2021-13', year:2021, subject:'po', topic:'po-4', type:'single', question:'个人与社会的关系最根本的是A.个人价值与社会价值 B.个人利益与社会利益C.个人理想与社会理想 D.个人存在与社会存在', options:["A. 个人价值与社会价值 B.个人利益与社会利益C.个人理想与社会理想 D.个人存在与社会存在"], answer:'B', analysis:'个人与社会的关系，归根到底是个人利益与社会整体利益的关系，社会利益离不开个人利益，个人利益也离不开社会利益，社会利益体现了作为社会成员的个人的根本利益和长远利益，是个人利益得以实现的前提和基础。故选 B。' },
  { id:'pol-2021-14', year:2021, subject:'po', topic:'po-4', type:'single', question:'新时代爱国主义教育的着力点是A.坚持实现中华民族伟大复兴的中国梦 B.坚持依法治国和以德治国相结合C.坚持祖国统一和民族团结 D.坚持立足中国又面向世界', options:["A. 坚持实现中华民族伟大复兴的中国梦 B.坚持依法治国和以德治国相结合C.坚持祖国统一和民族团结 D.坚持立足中国又面向世界"], answer:'C', analysis:'这是《新时代爱国主义教育实施纲要》中的内容，其中坚持以维护祖国统一和民族团结为着力点，国家统一和民族团结是中华民族根本利益所在。故正确答案是 C。其中A 选项是新时代爱国主义教育的鲜明主题：B 选项是坚持走中国特色社会主义法治道路的具体要求：D 选项是新时代爱国主义的基本要求。' },
  { id:'pol-2021-15', year:2021, subject:'po', topic:'po-5', type:'single', question:'北斗三号全球卫星导航系统建成并开通服务，标志着A.我国卫星导航系统实现了零的突破B.我国成为世界上第三个独立拥有全球卫星导航系统的国家C.世界所有国家都已使用我国北斗导航系统D.我国全球卫星导航系统重设实现了第二步目标', options:["A. 我国卫星导航系统实现了零的突破B.我国成为世界上第三个独立拥有全球卫星导航系统的国家C.世界所有国家都已使用我国北斗导航系统D.我国全球卫星导航系统重设实现了第二步目标"], answer:'B', analysis:'北斗三号全球卫星导航系统全面建成并开通服务，标志着工程“三步走 ”发展战略取得决战决胜，我国成为世界上第三个独立拥有全球卫星导航系统的国家。故正确答案选 B。16.2020 年全球服务服装贸易会于9 月 4 日-9 日在北京成功举办。本届服贸会的主题是：A.文化融合，创新发展 B.开放包容，团结合作C.齐心协力，携手前行 D.全球服务，互惠共享【答案】D【解析】时政主题无需解释二、多选题' },
  { id:'pol-2021-17', year:2021, subject:'po', topic:'po-1', type:'multi', question:'最近，科学家利用宇三结地柔发配今最大的宇宙结构之一，包含了数十万星系长达 14 亿光年的“南板堪 ”，中国科学表示由于方有引力，空度较高的区双会产生较弱的引力，将周围物质吸引进来形成了星系以及更大尺度的结构，现代宇宙学表明，宇由是由培物质，能器主导的，但物质究竟是什么，目前不得而知，在南极考 ”等宇走大尺度结构中，很可能看大量的昭物质，这是宇宙演化妃的重要指针，“南极塔 ”的发展表明A.未知世界与已知世界是客观存在的B.整个物质世界的时间查们是有限的C.世界本质量琦的反彩量D.世界只有尚末认知之物，没有不可认识之物', options:["A. 未知世界与已知世界是客观存在的B.整个物质世界的时间查们是有限的C.世界本质量琦的反彩量D.世界只有尚末认知之物，没有不可认识之物"], answer:'AD', analysis:'A 选项正确，世界是客观存在的，无论是未知世界还是已知世界都有着不以人的意志为转移的客观实在性。B 选项有误，时间和空间是有限与无限的统一，具体物质的时空是有限的，而整个物质世界的时空是无限的。C 选项有误,世界是物质的世界,世界的本质是客观实在性。D 选项正确，马克思主义坚持可知论的立场，认为世界只有尚未认识之物，而没有不可认识之物。' },
  { id:'pol-2021-18', year:2021, subject:'po', topic:'po-1', type:'multi', question:'人体是抗击毒的“机 ”，当房康体进入体，升高的体温刺激免疫系统打败毒，在想的青况下，免疫统创造了一个环境让概原体，难以生存，一病原体适应更高的度，人的免疫系统就无法挥作用，人时兑疫与自然环境之联系A.人类只能适应自然环境变化而不能改变自然环境B. 自然环境对人类发展有决定性作用C 自然是长发展的重要前提D，人在受自然制约的同时交环箱', options:["A. 人类只能适应自然环境变化而不能改变自然环境", "B. 自然环境对人类发展有决定性作用", "C. 自然是长发展的重要前提D，人在受自然制约的同时交环箱"], answer:'CD', analysis:'A 选项有误，人与自然是和谐共生的，人类的生存一方面要不断从自然界中获取对的生活资料，另一方面要适应自然的变化，同时，不像动物般的只能被动适应环境，人有主动性,人的生存活动具有自主性,可以积极主动的改造自然。B 选项有误，人类生存发展的决定性因素是物资资料的生产及生产方式。' },
  { id:'pol-2021-19', year:2021, subject:'po', topic:'po-1', type:'multi', question:'商品经济是一定社会历史条件的产物，商品经济得以产生的社会历史条件A.生产资料和劳动产品，于不同所有者B.社会分工的出现及其存在C.商品具有了使用价便打价便两个因素D.交换过程中形成了充当一般等价物的商品', options:["A. 生产资料和劳动产品，于不同所有者B.社会分工的出现及其存在C.商品具有了使用价便打价便两个因素D.交换过程中形成了充当一般等价物的商品"], answer:'AB', analysis:'商品经济得以产生的历史条件，一是社会发展分工的出现，二是生产资料和劳动产品分属于不同所有者。' },
  { id:'pol-2021-20', year:2021, subject:'po', topic:'po-1', type:'multi', question:'为了实观盈利，将人二流水线改造成机器流水线，受经济危机，从市场上采购生产原料，格下烽，资本构成发生变化的是A.资本有机构成 B.资本累构成 C.资本技术构成 D.资本技术构成', options:["A. 资本有机构成 B.资本累构成 C.资本技术构成 D.资本技术构成"], answer:'ACD', analysis:'人工流水线改造成为机器流水线,提高了生产的技术水平和生产的效率，将会引起资本技术构成发生变化。同时，由于生产原料价格的变化会直接引起资本价值构成的变化，因此，资本技术构成及价值构成的变化最终会引起资本有机构成的变化，因此正确答案选 ACD。21.1871 巴黎公社革命，马、恩总结的经验主要有A.无产阶级政权是为人民服务的机关B.必须为碎旧的国家机器建立无产阶级政权C.无产阶级革命取得成功并保持果实的首要条件是要有革命的武装D.必须建立无产阶级政党，发挥党的政治领导作用【答案】ABCD【解析】1871 年 3 月，巴黎公社起义胜利后，巴黎人民立即开始了建立无产阶级政权的尝试，但是巴黎公社仅存了 72 天。马克思高度评价巴黎公社的意义，认为公社的原则是永存的。马、恩总结巴黎公社经验指出，（1）无产阶级革命取得成功并保持胜利果实的首要条件是要有革命的武装；（2）必须打碎旧的国家机器，建立无产阶级的新型国家 无产' },
  { id:'pol-2021-22', year:2021, subject:'po', topic:'po-2', type:'multi', question:'社会主义基本制度确立以后，如何在中国这一个经济文化比较落后的东方大国建设和巩固社会主义：是党面临的一项崭新课题.为找到一条适合中国国情的社会主义建设道路，总带领人民进行了艰难曲折的初步探索。这一份初步探索的意义主要体现在A.体现了马克思主义中国化的第二次飞跃B.丰富了科学社会主义的理论和实践C.巩固和发展了我国社会主义制度D.为开创中国特色社会主义提供了宝贵经验，理论准备，物质基础', options:["A. 体现了马克思主义中国化的第二次飞跃B.丰富了科学社会主义的理论和实践C.巩固和发展了我国社会主义制度D.为开创中国特色社会主义提供了宝贵经验，理论准备，物质基础"], answer:'BCD', analysis:'本题主要考察社会主义制度确立的意义，A 选项，体现了马克思主义中国化的第二次飞跃，是错误的，第二次结合并没有实现，所以无法提及飞跃，故A 选项错误。社会主义制度的确立，为找到一条适合中国国情的社会主义建设道路，丰富了科学社会主义的理论实践，巩固和发展了我国社会主义制度，开创了中国特色社会主义提供了宝贵经验，理论准备，物质基础。故正确答案是 BCD。' },
  { id:'pol-2021-23', year:2021, subject:'po', topic:'po-2', type:'multi', question:'我国经济发展新动能的持续壮大声明A.创新驱动了引领作用进一步加强B.供给的结构效果取得了显著绩效C.数字经济已成为我国经济高质量发展的新引擎D.现代化经济已经生成', options:["A. 创新驱动了引领作用进一步加强B.供给的结构效果取得了显著绩效C.数字经济已成为我国经济高质量发展的新引擎D.现代化经济已经生成"], answer:'AB', analysis:'CD 不符合我国当前发展的实际，数字经济正成为，我国经济高质量发展的新引擎，并不是已经成为。同时，2035 年建成现代化经济体系。故正确答案为 AB。' },
  { id:'pol-2021-24', year:2021, subject:'po', topic:'po-2', type:'multi', question:'十三五时期我国大气污染治理取得了明显成效，主要得益于?A.坚特全民共治，全民防治B.把突出环境问题作为生态文明建设的看力点C.构建生态通道的生物多样性保护网络D.不断完善生态环境保护制度和强化环保监督', options:["A. 坚特全民共治，全民防治B.把突出环境问题作为生态文明建设的看力点C.构建生态通道的生物多样性保护网络D.不断完善生态环境保护制度和强化环保监督"], answer:'BCD', analysis:'A 选项表述有误，十九大报告表述是大气污染防治攻坚战秉持的是全民共治，源头防治。把突出环境问题作为生态文明建设的着力点，构建生态通道的生物多样性保护网络，不断完善生态环境保护制度和强化环保监督是我国在十三五时期大气污染治理领域取得明显成效的主要原因。故正确答案 BCD。' },
  { id:'pol-2021-25', year:2021, subject:'po', topic:'po-2', type:'multi', question:'我国提高就业质量的主要举措是A.开展大规模职业技能培训 B.提供全方位公共就业服务C.构建和谐劳动关系 D.使失业率保持合理区间', options:["A. 开展大规模职业技能培训 B.提供全方位公共就业服务C.构建和谐劳动关系 D.使失业率保持合理区间"], answer:'ABC', analysis:'我国提高就业质量的主要举措是：开展大舰模职业技能信训，提供全方位公共就业服务，构建和谐劳动关系，D 选项表述有误，是实现就业的目标，不属于提高就业质量的举措。故正确答案 ABC。' },
  { id:'pol-2021-26', year:2021, subject:'po', topic:'po-2', type:'multi', question:'促进各民族像石榴籽一样紧紧抱在一起旨在A.铸牢中华民族共同意识B.建设各民族共有精神家园C.巩固和发展平等团结互助和谐社会的社会主义民族关系D.使各民族在中华民族大家庭手足相亲，守望相助', options:["A. 铸牢中华民族共同意识B.建设各民族共有精神家园C.巩固和发展平等团结互助和谐社会的社会主义民族关系D.使各民族在中华民族大家庭手足相亲，守望相助"], answer:'ABCD', analysis:'本题考查内容结合时政，选自习总书记出席全国民族团结进步表彰大会并发表题为《促进各民族像石榴籽一样紧紧拥抱在一起》的重要讲话，要以铸牢中华民族共同体意识为主线，全面贯彻党的民族理论和民族政策，坚持共同团结奋斗、共同繁荣发展，把民族团结进步事业作为基础性事业抓紧抓好，促进各民族像石榴籽一样紧紧拥抱在一起，推动中华民族走向包容性更强、凝聚力更大的命运共同体，共建美好家园，共创美好未来。建设各民族共有精神家园，巩固和发展平等团结互助和谐社会的社会主义民族关系，使各民族在中华民族大家庭手足相亲，守望相助。故正确答案为 ABCD。' },
  { id:'pol-2021-27', year:2021, subject:'po', topic:'po-3', type:'multi', question:'鸦片战争成为中国近代史起点是因为随着西方列强入侵A.中国封建社会逐渐变成了半殖民地半封建社会B.中国开始善于西方资本主义国家C.中国人民逐渐开始反帝反封建的资产主义革命D.无产阶级与资产阶级的矛盾上升为占支配地位的主要矛盾', options:["A. 中国封建社会逐渐变成了半殖民地半封建社会B.中国开始善于西方资本主义国家C.中国人民逐渐开始反帝反封建的资产主义革命D.无产阶级与资产阶级的矛盾上升为占支配地位的主要矛盾"], answer:'AC', analysis:'鸦片战争中，清政府战败，签订了《南京条约》，不平等条约的签订破坏了中国主权、领土等多项主权，由于帝国主义的入侵，中国社会开始沦为半殖民地半封建社主义同中华民族，封建主义同人民大众的始了反帝反封建的资产阶级革命。因此鸦片战争成为近代史的起点。' },
  { id:'pol-2021-28', year:2021, subject:'po', topic:'po-3', type:'multi', question:'五四运动后，社会主义思潮在中国蓬勃兴起，马克思主义开始在知识界得到传播。中国早期信仰马克思主义的人物，就类型而言，主要包括：A.五四运动的左翼骨干B.五四以前的新文化运动的精神领袖C.原中国同盟会会员，辛亥革命时期的活动家D.工人群众中的活跃分子', options:["A. 五四运动的左翼骨干B.五四以前的新文化运动的精神领袖C.原中国同盟会会员，辛亥革命时期的活动家D.工人群众中的活跃分子"], answer:'ABC', analysis:'中国早期信仰马克思主义的人物，主要包括：五四运动的左翼骨干、五四以前的新文化运动的精神领袖、原中国同盟会会员，辛亥革命时期的活动家。' },
  { id:'pol-2021-29', year:2021, subject:'po', topic:'po-3', type:'multi', question:'中国从开始全面建设社会主义到 1976 年尽管经历过严重的曲折，但从总体上来说，社会主义建设取得的成就是显著的，主要表现在A.人民生活水平的提高与文化教育，医疗，科技事业的发展B.独立完整的工业体系的建立和国民体系的建设C.国际地位的提高与国际环境的改善D.探索中形成的建设社会主义的若干重要原则', options:["A. 人民生活水平的提高与文化教育，医疗，科技事业的发展B.独立完整的工业体系的建立和国民体系的建设C.国际地位的提高与国际环境的改善D.探索中形成的建设社会主义的若干重要原则"], answer:'ABCD', analysis:'1956 年中国确立了社会主义基本制度之后，中国开启了建设社会主义的时期，在社会主义建设时期取得的成就是显著的，主要表现在；（1）人民生活水平的提高与文化教育，医疗，科技事业的发展；（2）独立完整的工业体系的建立和国民体系的建设；（3）国际地位的提高与国际环境的改善；（4）探素中形成的建设会主义的若干重要原则。30.2020 年颁布的《中华人民共和国民法典》是新中国第一部以法典命名的法律，这部法典共七编，1260 条，包括总则、物权、合同、人格权、婚姻、家庭、继承、侵权责任以及附则。被称为“社会生活的百科全书 ”。它系统地整合了新中国成立七十多年来司法实践中形成的民事法律规范，汲取和借鉴了中外优势法治建设的有益成果，是一部具有鲜明中国特色、实践特色、时代特色的民法典，开创了我国法典编纂立法的先河。编纂民法典的重大意义是：A.推进全面依法治国，推进国家法律体系和治理能力现代化的重大举措B.坚持和完善中国特色社会主义制度的现实需求C.坚持和完善社会主义基本经济制度、推动经济高质量发展的客观要求D.增进人民福祉，维护广大人民根本利益的必然要求【答案】ABCD【解析】时政与思修结合考察。关于《中华人民共和国民法典(草案)》的说明中，提及编撰民法典的四点意义。原文出现。' },
  { id:'pol-2021-31', year:2021, subject:'po', topic:'po-4', type:'multi', question:'法律权威是指法律再社会中的作用力、影响力和公信力，是法律应有的尊严和生命，法律是否具有权威取决于 ( )A.法律再时间中的实施程度B.法律本身的科学程度C.法律在国家和社会治理体系中的地位和作用D.法律被国际社会认同和尊崇的程度', options:["A. 法律再时间中的实施程度B.法律本身的科学程度C.法律在国家和社会治理体系中的地位和作用D.法律被国际社会认同和尊崇的程度"], answer:'ABC', analysis:'D 选项应该改为“法律被社会成员尊崇或信仰的程度 ”，故不选。32.2020 年 6 月 30 日，十三届全国人大常委会第二十次会议表决通过的《中国人民共和国香港特别行政区维护国家安全法》，是新形势下坚持和完善“一国两制 ”制度体系的标志性法律，其重大作用在于 ( )A.有效应对各种反中乱港势力B.确保国家主权在香港收到严格保护C.弥补香港国安方面的立法缺失D.保障香港长治久安和长期繁荣稳定【答案】ABCD【解析】时政题。十三届全国人大常委会第十九次会议作关于《中华人民共和国香港特别行政区维护国家安全法（草案）》中原文呈现，编撰国安法的意义和作用。33.2020.11.15，东盟 16 国与中，日，韩，澳和新西兰正式签署《区域全面经济伙伴关系稳定》（RECP），全球最大贸易区诞生其重要意义主要体现在 ( )A.将为区域乃至全球经济复苏注入新动能B.开启了区域经济一体化新篇章C.全球贸易投资自由化、便利化取得压倒性优势D.将更好地发挥中国作为亚太地区价值新中心节点作用【答案】ABCD【解析】中国加入 RECP 对中国和世界的发展都具有重要的的意义。包括多边主义和自由贸易的胜利、进一步提升亚太地区今后在全球发展格局中的分量、将为区域和全球经济增长注入强劲动力也是中国更高水平对外开放的重要平台。RCEP将促进亚太地区价值链整合，推动地区经贸一体化发展，也将更好发挥中国作为亚太地区价值链中心节点的作用，使亚太地区各个经济体、全球其他经济体，都从中国经济增长以及亚太地区经济恢复中受益。三、材料分析题。34~38 小题，每小题 10 分，共 50 分。要求结合所学知识分析材料。' },
  { id:'pol-2021-34', year:2021, subject:'po', topic:'po-1', type:'essay', question:'（马原）材料：第 1 段：当今世界正经历百年未有之大变局，不稳定性不确定性明显增强（首句）第 4 段：只有准确把我分析我国发展阶段、环境、条件变化、看清变局本质和发展大势，顺势而为，谋事而动，提升危中寻机，化危为机的能力，沉着应对变局，开拓新局，集中力量办好自己的事，推动形成新发展格局，才能牢牢把握化危为机的主动权，为不确定的世界增加确定性。（末句）摘自《人民日报》（2020年 4 月 3 日、4 月 16 日、9 月 25 日）（1）分析在“危机中育新机，于变局中开新局 ”，这一论断蕴含的唯物辩证理论 。（5 分）解析：“在危机中育新机，于变局中开新局 ”这一论断蕴含的唯物辩证法原理为事物内部和事物之间存在着对立统一的关系。事物内部和事物之间存在对立统一关系，也即矛盾关系。矛盾双方具有同一性和斗争性双重属性。同一性是指矛盾双方相互依存、相互贯通的性质和趋势。它具有两个方面的含义：一是矛盾着的对立面相互依存，互为存在的条件，并处于一个统一体中；二是矛盾着的对立面之间相互贯通，在一定条件下相互转化。材料中所提及的“危 ”与“机 ”作为矛盾的双方，二者相伴而生、相互依存、相互转化。这就需要', options:[], answer:'', analysis:'' },
  { id:'pol-2021-35', year:2021, subject:'po', topic:'po-2', type:'essay', question:'（毛中特）1.从人民生活水平不断提高的视角，分析我国从“解决温饱 ”到“达到小康水平 ”再到“全面达成小康社会 ”中体现的中国特色社会主义制度优势。（6 分）解析：（1）①全面建成小康社会是我们党向人民、向历史作出的庄严承诺，是14 亿中国人民的共同期盼,中国共产党人的初心和使命，就是为中国人民谋幸福，为中华民族谋复兴。②全面建成小康社会为实现中华民族伟大复兴中国梦夯实基础，在中华民族发展史上，全面建成小康社会是关键一步，它延续着中华民族源远流长的盛世期盼和对美好生活的向往，又为民族的伟大复兴奠定了坚实的基础，继往开来，既是胜利的丰碑，又是进一步发展的起点。③全面建成小康社会是中华民族发展史上的光辉时刻，它意味着中华民族作为一个民族整体摆脱了绝对贫困，两千多年来世代追求的小康梦想得以真正实现。（2）①全面建成小康社会，最艰巨的任务是脱贫攻坚，最突出的短板在于农村贫困人口。②消除贫困、改善民生、实现共同富裕，是中国特色社会主义的本质要求，是彰显社会主义优越性的体现。③2020 年脱贫攻坚任务完成后，我国将历史性地解决困扰中华民族几千年的绝对贫困问题，在共同富裕的道路上迈出坚实一步，对中国', options:[], answer:'', analysis:'' },
  { id:'pol-2021-36', year:2021, subject:'po', topic:'po-3', type:'essay', question:'材料：第 1 段：1950 年 6 月朝鲜内战爆发。（首）第 5 段：抗美援朝战争伟大胜利，是中国人民站起来站立于世界东方的宣言书，是中华民族走向伟大复兴的主要里程碑，对中国和世界都有重大而深远的意义。摘自《习在纪念中国人民志愿军抗美援朝出国作战 70 周年大会上的讲话》（1）“党和政府作出抗美援朝，保家卫国的历史性决策需要“非凡的气魄和胆略 ”请结合新中国成立初期的形式和党的任务，加以分析说明。（5 分）解析：（1）建国初期，我国面临着许多严重的困难和紧迫的问题，解放全中国的任务还没有完全结束，中国经济十分落后，以美国为首的西方资本主义阵营企图通过强硬的措施搞垮中国，所以新生的中国面临着两大历史任务，一是继续完成新民主主义革命遗留任务，二是动员人民去医治战争的创伤，恢复国民经济。美国政府从其全球战略和冷战思维出发，做出武装干涉朝鲜内政的决定，并派出第七舰队侵入台湾海峡，1950 年美国不顾中国政府的警告，悍然越过三八线，将战火烧到中朝边境。当时，美国作为世界上的超级大国之一，无论在经济和军事方面都优于中国，尽管当时中美两国的军事和经济力量悬殊，但是，当美国侵略军把战火烧到鸭绿江边的时', options:[], answer:'', analysis:'' },
  { id:'pol-2021-37', year:2021, subject:'po', topic:'po-4', type:'essay', question:'（思修法基）材料：1979 年 12 月 6 日，邓同志在会见日本首相大平正芳时谈到了二十世纪末我过的奋斗目标：“我们要实现四个现代化，是中国式的现代化 ”（首）第 2 段：党的十九届五中全会通过的《中共中央关于制定 目标的建议》宣告：” \'十三五\'规划目标任务即将完成 社会主义中国以更加雄伟的（末）身姿屹立于世界东方。 ”摘编自《人民日报》（2020 年 7 月 15 日、11 月 4 日）“人对美好生活的向往，就是我们的奋斗目标。”这是恢弘壮丽的新征程，又是任重道远的新征程。）摘自《人民日报》（2020 年 6 月 30 日，7 月 20 日）（1）中国抗疫精神是中国精神的生动诠释，“全国人民都在为“武汉热干面&quot;加油&quot;，其中体现了什么样的中国精神?解析：在这场同严重疫情的殊死较量中，中国人民和中华民族以敢于斗争、敢于胜利的大无畏气概，铸就了生命至上、举国同心、舍生忘死、尊重科学、命运与共的伟大抗疫精神。第一，生命至上，集中体现了中国人民深厚的仁爱传统和中国共产党人以人民为中心的价值追求。第二，举国同心，集中体现了中国人民万众一心、同甘共苦的团结伟力。第三，舍生忘', options:[], answer:'', analysis:'' },
  { id:'pol-2021-38', year:2021, subject:'po', topic:'po-5', type:'essay', question:'（时政）（1）分析中国和美国两国在面对国际组织和国际事务的不同态度，并指出其本质。【材料里主要写的是美国退出来很多国际组织，而中国积极参与国际组织和事物，疫情期间捐款，并在 2 年中陆续捐款 20 亿美元物资等，疫苗研制成功会在全球范围内推广使用】解析：大道之行，天下为公。当今世界，各国相互依存、休戚与共，越来越成为你中有我，我中有你的命 运共同体。面对人类面临的挑战，世界各国应该加强团结而不是制造隔阂、推进合作而不是挑起冲突，携手共建人类命运共同体，造福世界各国人民。美国退出诸多国际组织和事务，在政治上干涉其他国家的内政，侵犯其他国家的主权和领土完整，严重违反了联合国宪章精神，破坏了世界的和平与稳定。是霸权主义强权政治的表现。在经济上奉行单边主义、贸易保护主义、是全球经济复苏最大的不确定因素和风险源。中方秉持人类命运共同体理念，既对本国人民生命安全和身体健康负责，也对全球公共卫生事业尽责，采取了最全面、最彻底、最严格的防控举措，打响了疫情防控的人民战争、总体战、阻击战，构建起防止病毒国际传播的强有力第一道防线，有效阻止了疫情在全球范围的蔓延，为世界各国防控疫情争取了宝贵时间，为世界公', options:[], answer:'', analysis:'' },
];
